import sqlite3

def construct_query(clauses):
    if not clauses:
        return "SELECT * FROM users", []

    query_parts = []
    params = []

    for clause in clauses:
        field = clause['field']
        operator = clause['op']
        value = clause['value']

        # Handle LIKE operator
        if operator == 'LIKE':
            query_parts.append(f"{field} {operator} ?")
            params.append(f"%{value}%")
        else:
            query_parts.append(f"{field} {operator} ?")
            params.append(value)

    full_query = "SELECT * FROM users WHERE " + " AND ".join(query_parts)
    return full_query, params

def search(clauses):
    query, params = construct_query(clauses)
    
    # Connect to the database
    conn = sqlite3.connect('example.db')
    cursor = conn.cursor()

    try:
        # Execute the query
        cursor.execute(query, params)
        results = cursor.fetchall()
    finally:
        # Close the connection
        conn.close()

    return results

# Example usage
